        "b": [2, 20, None],    # d1, d2, d3 (missing)
        "c": [None, 30, 300], # d1 (missing), d2, d3
    }


def test_zip_dicts_happy_path_single_dict():
    d = {"x": 7, "y": 8}
    result = zip_dicts(d)

    assert result == {"x": [7], "y": [8]}


def test_zip_dicts_edge_case_no_dicts_returns_empty_dict():
    result = zip_dicts()
    assert result == {}


def test_zip_dicts_edge_case_all_dicts_empty():
    result = zip_dicts({}, {}, {})
    assert result == {}


def test_zip_dicts_edge_case_key_present_in_only_one_dict():
    d1 = {"only": "first"}
    d2 = {}
    d3 = {}
    result = zip_dicts(d1, d2, d3)

    assert result == {"only": ["first", None, None]}


def test_zip_dicts_edge_case_mixed_value_types():
    d1 = {"k": None}
    d2 = {"k": [1, 2, 3]}
    result = zip_dicts(d1, d2)

    assert result == {"k": [None, [1, 2, 3]]}


def test_zip_dicts_error_case_non_dict_argument_raises_attribute_error():
    # Accessing d.get(...) will fail for non-dicts.
    with pytest.raises(AttributeError):
        zip_dicts({"a": 1}, ["not-a-dict"])


def test_zip_dicts_error_case_at_least_one_argument_is_none_raises_attribute_error():
    with pytest.raises(AttributeError):
        zip_dicts(None)


def test_zip_dicts_error_case_non_hashable_dict_argument_raises_type_error_on_union():
    # The function attempts: set().union(*dicts)
    # Passing a non-hashable mapping (e.g., a list) to union triggers TypeError.
    with pytest.raises(TypeError):
        zip_dicts(["not-a-dict"])
